package weekelyAssignment1;

public class MarksConversion {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		
		float marks=87.6f;
		System.out.println("Float Marks: "+marks);
		
		double stu_marks= marks;
		System.out.println("double marks: "+stu_marks);
		
		int marks1=(int)marks;
		System.out.println("int marks: "+marks1);
		
		char value=(char)marks1;
		System.out.println("ASCII_VALUE: "+value);
		

	}

}
